  "inlineSchema": "// Sistema de Almacenes (multi-almacen) — Institucion Publica\n// Paso 2 del roadmap: catalogo y usuarios. NO incluye aun stock/ingresos/egresos/kardex.\n// Docs: ver CLAUDE.md en la raiz del repo.\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"../src/generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ---------------------------------------------------------------------------\n// Enums\n// ---------------------------------------------------------------------------\n\nenum Rol {\n  super_admin\n  admin\n  solicitador\n  aprobador\n  responsable_almacen\n  central\n  observador_almacen\n}\n\n// ---------------------------------------------------------------------------\n// Entidades\n// ---------------------------------------------------------------------------\n\n/// Area administrativa (ej. Unidad de Planificacion).\nmodel Unidad {\n  id     Int     @id @default(autoincrement())\n  nombre String  @unique\n  sigla  String  @unique\n  activo Boolean @default(true)\n\n  usuarios Usuario[]\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"unidades\")\n}\n\n/// Almacen fisico. La institucion tiene 9+.\nmodel Almacen {\n  id     Int     @id @default(autoincrement())\n  nombre String  @unique\n  activo Boolean @default(true)\n\n  usuarios     Usuario[]\n  observadores UsuarioAlmacenObservado[]\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"almacenes\")\n}\n\n/// Usuario del sistema. Se crea solo desde el modulo usuarios (no hay registro publico).\n/// unidadId y almacenId son independientes entre si y opcionales segun el rol:\n///   - super_admin / admin: sin unidad ni almacen.\n///   - solicitador: unidad + almacen requeridos.\n///   - aprobador: unidad requerida (unico activo por unidad).\n///   - responsable_almacen / central: almacen requerido (unico activo por almacen).\n///   - observador_almacen: sin almacen fijo (usa UsuarioAlmacenObservado).\nmodel Usuario {\n  id       Int     @id @default(autoincrement())\n  nombre   String\n  usuario  String  @unique\n  password String\n  rol      Rol\n  activo   Boolean @default(true)\n\n  unidadId  Int?     @map(\"unidad_id\")\n  unidad    Unidad?  @relation(fields: [unidadId], references: [id])\n  almacenId Int?     @map(\"almacen_id\")\n  almacen   Almacen? @relation(fields: [almacenId], references: [id])\n\n  almacenesObservados UsuarioAlmacenObservado[]\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@index([unidadId])\n  @@index([almacenId])\n  @@map(\"usuarios\")\n}\n\n/// Tabla intermedia (muchos-a-muchos) para los almacenes que un observador_almacen puede ver.\nmodel UsuarioAlmacenObservado {\n  id        Int @id @default(autoincrement())\n  usuarioId Int @map(\"usuario_id\")\n  almacenId Int @map(\"almacen_id\")\n\n  usuario Usuario @relation(fields: [usuarioId], references: [id], onDelete: Cascade)\n  almacen Almacen @relation(fields: [almacenId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@unique([usuarioId, almacenId])\n  @@index([almacenId])\n  @@map(\"usuario_almacen_observado\")\n}\n\n/// Clasificador por Objeto del Gasto (jerarquico, hasta 5 niveles).\n/// NO se crea a mano: se importa/semilla desde el documento oficial (ver prisma/seed.ts).\n/// nivel = 5 - (cantidad de ceros finales del codigo de 5 digitos).\n/// seleccionable = true SOLO en nodos hoja (los unicos asignables a un Item).\nmodel Partida {\n  id                Int     @id @default(autoincrement())\n  codigo            String  @unique\n  denominacion      String\n  nivel             Int\n  seleccionable     Boolean @default(false)\n  activo            Boolean @default(true)\n  ultimoCorrelativo Int     @default(0) @map(\"ultimo_correlativo\")\n\n  padreId Int?      @map(\"padre_id\")\n  padre   Partida?  @relation(\"PartidaJerarquia\", fields: [padreId], references: [id])\n  hijos   Partida[] @relation(\"PartidaJerarquia\")\n\n  items Item[]\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@index([padreId])\n  @@map(\"partidas\")\n}\n\n/// Proveedor de la institucion. Sera referenciado por Ingreso (fase posterior),\n/// por eso nunca se borra: baja logica via `activo`.\n/// nit es opcional (hay proveedores sin NIT) pero unico cuando existe:\n/// Postgres admite multiples NULL en un indice unico.\nmodel Proveedor {\n  id        Int     @id @default(autoincrement())\n  nombre    String\n  nit       String? @unique\n  telefono  String?\n  /// Nombre de la persona de contacto (ej. \"Juan Perez, ejecutivo de ventas\").\n  contacto  String?\n  direccion String?\n  activo    Boolean @default(true)\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"proveedores\")\n}\n\n/// Item real de almacen (catalogo compartido entre todos los almacenes).\n/// codigo autogenerado al crear: {partida.codigo}-{correlativo padStart(6)} (ej. \"39700-000001\").\n/// El stock NO vive aqui (ira en StockAlmacen, fase posterior).\nmodel Item {\n  id           Int     @id @default(autoincrement())\n  codigo       String  @unique\n  descripcion  String\n  unidadMedida String  @map(\"unidad_medida\")\n  // Ruta publica relativa de la imagen referencial (ej. \"/uploads/items/12-a3f9.webp\").\n  // Null = sin imagen. El binario vive en el filesystem, no en la DB.\n  imagenUrl    String? @map(\"imagen_url\")\n  activo       Boolean @default(true)\n\n  partidaId Int     @map(\"partida_id\")\n  partida   Partida @relation(fields: [partidaId], references: [id])\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@index([partidaId])\n  @@map(\"items\")\n}\n",
